417→// ---------------------------------------------------------------------------
418→// getOrchestratorSessionStatus
419→// ---------------------------------------------------------------------------
420→
421→type GetStatusInput = {
422→  surreal: Surreal;
423→  sessionId: string;
424→};
425→
426→export async function getOrchestratorSessionStatus(
427→  input: GetStatusInput,
428→): Promise<SessionStatusResult> {
429→  const lookup = await lookupSession(input.surreal, input.sessionId);
430→  if (!lookup.ok) {
431→    return { ok: false, error: lookup.error };
432→  }
433→  const { session } = lookup;
434→
435→  return {
436→    ok: true,
437→    value: {
438→      orchestratorStatus: lookup.status,
439→      ...pickDefined({
440→        worktreeBranch: session.worktree_branch,
441→        worktreePath: session.worktree_path,
442→        startedAt: session.started_at,
443→        lastEventAt: session.last_event_at,
444→        error: session.error,
445→      }),
446→    },
447→  };
448→}
449→
450→// ---------------------------------------------------------------------------
451→// abortOrchestratorSession
452→// ---------------------------------------------------------------------------
453→
454→type AbortSessionInput = {
455→  surreal: Surreal;
456→  shellExec: ShellExec;
457→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
458→  sessionId: string;
459→  endAgentSession: (input: {
460→    surreal: Surreal;
461→    workspaceRecord: RecordId<"workspace", string>;
462→    sessionId: string;
463→    summary: string;
464→  }) => Promise<{ session_id: string; ended: boolean }>;
465→};
466→
467→export async function abortOrchestratorSession(
468→  input: AbortSessionInput,
469→): Promise<AbortSessionResult> {
470→  const lookup = await lookupSession(input.surreal, input.sessionId);
471→  if (!lookup.ok) {
472→    return { ok: false, error: lookup.error };
473→  }
474→  const { session, record: sessionRecord } = lookup;
475→
476→  // 1. Abort the agent process if handle exists
477→  const handle = handleRegistry.get(input.sessionId);
478→  if (handle) {
479→    handle.abort();
480→    handleRegistry.delete(input.sessionId);
481→  }
482→
483→  // 2. Update orchestrator_status to aborted
484→  await input.surreal.update(sessionRecord).merge({
485→    orchestrator_status: "aborted" as OrchestratorStatus,
486→  });
487→
488→  const workspaceRecord = requireWorkspace(session, input.sessionId);
489→
490→  // 3. Remove worktree if branch name exists
491→  if (session.worktree_branch) {
492→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
493→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
494→  }
495→
496→  // 4. Return task to ready
497→  if (session.task_id) {
498→    await input.surreal.update(session.task_id).merge({
499→      status: "ready",
500→      updated_at: new Date(),
501→    });
502→  }
503→
504→  // 5. End the agent session
505→  await input.endAgentSession({
506→    surreal: input.surreal,
507→    workspaceRecord,
508→    sessionId: input.sessionId,
509→    summary: "Session aborted",
510→  });
511→
512→  return {
513→    ok: true,
514→    value: {
515→      aborted: true,
516→      sessionId: input.sessionId,
517→    },
518→  };
519→}
520→
521→// ---------------------------------------------------------------------------
522→// acceptOrchestratorSession
523→// ---------------------------------------------------------------------------
524→
525→type AcceptSessionInput = {
526→  surreal: Surreal;
527→  sessionId: string;
528→  summary: string;
529→  endAgentSession: (input: {
530→    surreal: Surreal;
531→    workspaceRecord: RecordId<"workspace", string>;
532→    sessionId: string;
533→    summary: string;
534→  }) => Promise<{ session_id: string; ended: boolean }>;
535→};
536→
537→export async function acceptOrchestratorSession(
538→  input: AcceptSessionInput,
539→): Promise<AcceptSessionResult> {
540→  const lookup = await lookupSession(input.surreal, input.sessionId);
541→  if (!lookup.ok) {
542→    return { ok: false, error: lookup.error };
543→  }
544→  const { session, record: sessionRecord, status } = lookup;
545→
546→  if (!ACCEPTABLE_STATUSES.has(status)) {
547→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
548→  }
549→
550→  const workspaceRecord = requireWorkspace(session, input.sessionId);
551→
552→  // 1. Update orchestrator_status to completed
553→  await input.surreal.update(sessionRecord).merge({
554→    orchestrator_status: "completed" as OrchestratorStatus,
555→  });
556→
557→  // 2. Mark task as done
558→  if (session.task_id) {
559→    await input.surreal.update(session.task_id).merge({
560→      status: "done",
561→      updated_at: new Date(),
562→    });
563→  }
564→
565→  // 3. Clean up handle registry
566→  handleRegistry.delete(input.sessionId);
567→
568→  // 4. End the agent session
569→  await input.endAgentSession({
570→    surreal: input.surreal,
571→    workspaceRecord,
572→    sessionId: input.sessionId,
573→    summary: input.summary,
574→  });
575→
576→  return {
577→    ok: true,
578→    value: {
579→      accepted: true,
580→      sessionId: input.sessionId,
581→    },
582→  };
583→}
584→
585→// ---------------------------------------------------------------------------
586→// State guard helpers
587→// ---------------------------------------------------------------------------
588→
589→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
590→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
591→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
592→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
593→
594→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
595→  return {
596→    code: "SESSION_ERROR",
597→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
598→    httpStatus: 409,
599→  };
600→}
601→
602→function sessionAborted(sessionId: string): SessionError {
603→  return {
604→    code: "SESSION_ERROR",
605→    message: `Session ${sessionId} has been aborted`,
606→    httpStatus: 409,
607→  };
608→}
609→
610→// ---------------------------------------------------------------------------
611→// getOrchestratorReview
612→// ---------------------------------------------------------------------------
613→
614→type GetReviewInput = {
615→  surreal: Surreal;
616→  sessionId: string;
617→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
618→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
619→  getTaskTitle: (taskId: string) => Promise<string>;
620→};
621→
622→export async function getOrchestratorReview(
623→  input: GetReviewInput,
624→): Promise<ReviewResult> {
625→  const lookup = await lookupSession(input.surreal, input.sessionId);
626→  if (!lookup.ok) {
627→    return { ok: false, error: lookup.error };
628→  }
629→  const { session, status } = lookup;
630→
631→  if (status === "aborted") {
632→    return { ok: false, error: sessionAborted(input.sessionId) };
633→  }
634→
635→  if (!REVIEWABLE_STATUSES.has(status)) {
636→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
637→  }
638→
639→  // Get diff from the branch
640→  const branchName = session.worktree_branch ?? "";
641→  const workspaceRecord = requireWorkspace(session, input.sessionId);
642→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
643→  const diffResult = await input.getDiff(repoRoot, branchName);
644→
645→  const diff = diffResult.ok
646→    ? diffResult.value
647→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
648→
649→  // Get task title
650→  const taskId = session.task_id ? session.task_id.id : "";
651→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
652→
653→  return {
654→    ok: true,
655→    value: {
656→      taskTitle,
657→      diff,
658→      session: {
659→        orchestratorStatus: status,
660→        ...pickDefined({
661→          worktreeBranch: session.worktree_branch,
662→          startedAt: session.started_at,
663→          lastEventAt: session.last_event_at,
664→        }),
665→      },
666→    },
667→  };
668→}
669→
670→// ---------------------------------------------------------------------------
671→// rejectOrchestratorSession
672→// ---------------------------------------------------------------------------
673→
674→type RejectSessionInput = {
675→  surreal: Surreal;
676→  sessionId: string;
677→  feedback: string;
678→};
679→
680→export async function rejectOrchestratorSession(
681→  input: RejectSessionInput,
682→): Promise<RejectSessionResult> {
683→  const lookup = await lookupSession(input.surreal, input.sessionId);
684→  if (!lookup.ok) {
685→    return { ok: false, error: lookup.error };
686→  }
687→  const { session, record: sessionRecord, status } = lookup;
688→
689→  if (!REJECTABLE_STATUSES.has(status)) {
690→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
691→  }
692→
693→  // 1. Update session status to active (agent resumes work)
694→  await input.surreal.update(sessionRecord).merge({
695→    orchestrator_status: "active" as OrchestratorStatus,
696→    last_feedback: input.feedback,
697→  });
698→
699→  // 2. Return task to in_progress
700→  if (session.task_id) {
701→    await input.surreal.update(session.task_id).merge({
702→      status: "in_progress",
703→      updated_at: new Date(),
704→    });
705→  }
706→
707→  return {
708→    ok: true,
709→    value: {
