526→export async function createAgentSession(input: {
527→  surreal: Surreal;
528→  agent: string;
529→  workspaceRecord: RecordId<"workspace", string>;
530→  projectRecord?: RecordId<"project", string>;
531→  taskId?: string;
532→}): Promise<{ session_id: string }> {
533→  const now = new Date();
534→  const sessionRecord = new RecordId("agent_session", randomUUID());
535→
536→  await input.surreal.create(sessionRecord).content({
537→    agent: input.agent,
538→    started_at: now,
539→    workspace: input.workspaceRecord,
540→    created_at: now,
541→    ...(input.projectRecord ? { project: input.projectRecord } : {}),
542→    ...(input.taskId ? { task_id: new RecordId("task", requireRawId(input.taskId, "task_id")) } : {}),
543→  });
544→
545→  // If task-scoped, link session to task and auto-promote status
546→  if (input.taskId) {
547→    const taskRecord = new RecordId("task", requireRawId(input.taskId, "task_id"));
548→    const task = await input.surreal.select<TaskRow>(taskRecord);
549→    if (!task) {
550→      throw new Error(`task not found: ${input.taskId}`);
551→    }
552→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
553→      throw new Error("task is outside the current workspace scope");
554→    }
555→    await input.surreal.update(taskRecord).merge({
556→      ...(task.status === "todo" || task.status === "ready"
557→        ? { status: "in_progress" }
558→        : {}),
559→      source_session: sessionRecord,
560→      updated_at: now,
561→    });
562→  }
563→
564→  return { session_id: toRawId(sessionRecord) };
565→}
