  3→export class BrainHttpClient {
  4→  private baseUrl: string;
  5→  private workspaceId: string;
  6→  private accessToken: string;
  7→  private refreshToken: string;
  8→  private tokenExpiresAt: number;
  9→  private clientId: string;
 10→
 11→  constructor(config: BrainConfig) {
 12→    this.baseUrl = config.server_url.replace(/\/$/, "");
 13→    this.workspaceId = config.workspace;
 14→    this.accessToken = config.access_token;
 15→    this.refreshToken = config.refresh_token;
 16→    this.tokenExpiresAt = config.token_expires_at;
 17→    this.clientId = config.client_id;
 18→  }
 19→
 20→  private async refreshTokenIfNeeded(): Promise<void> {
 21→    // Refresh 60 seconds before expiry
 22→    if (Date.now() < (this.tokenExpiresAt - 60) * 1000) return;
 23→
 24→    const res = await fetch(`${this.baseUrl}/api/auth/oauth2/token`, {
 25→      method: "POST",
 26→      headers: { "Content-Type": "application/x-www-form-urlencoded" },
 27→      body: new URLSearchParams({
 28→        grant_type: "refresh_token",
 29→        refresh_token: this.refreshToken,
 30→        client_id: this.clientId,
 31→        resource: this.baseUrl,
 32→      }),
 33→    });
 34→
 35→    if (!res.ok) {
 36→      throw new Error(`Token refresh failed: ${res.status}. Run 'brain init' to re-authenticate.`);
 37→    }
 38→
 39→    const data = await res.json() as {
 40→      access_token: string;
 41→      refresh_token?: string;
 42→      expires_in: number;
 43→    };
 44→
 45→    this.accessToken = data.access_token;
 46→    if (data.refresh_token) this.refreshToken = data.refresh_token;
 47→    this.tokenExpiresAt = Math.floor(Date.now() / 1000) + data.expires_in;
 48→
 49→    // Persist updated tokens
 50→    const gitRoot = findGitRoot(process.cwd());
 51→    const global = await loadGlobalConfig();
 52→    if (global && gitRoot && global.repos[gitRoot]) {
 53→      global.repos[gitRoot].access_token = this.accessToken;
 54→      if (data.refresh_token) global.repos[gitRoot].refresh_token = this.refreshToken;
 55→      global.repos[gitRoot].token_expires_at = this.tokenExpiresAt;
 56→      await saveGlobalConfig(global);
 57→    }
 58→  }
 59→
 60→  private async headers(): Promise<Record<string, string>> {
 61→    await this.refreshTokenIfNeeded();
 62→    return {
 63→      "Content-Type": "application/json",
 64→      Authorization: `Bearer ${this.accessToken}`,
 65→    };
 66→  }
