  7→
  8→export function createGitHubWebhookHandler(
  9→  deps: ServerDependencies,
 10→): (workspaceId: string, request: Request) => Promise<Response> {
 11→  return (workspaceId: string, request: Request) =>
 12→    handleGitHubWebhook(deps, workspaceId, request);
 13→}
 14→
 15→async function handleGitHubWebhook(
 16→  deps: ServerDependencies,
 17→  workspaceId: string,
 18→  request: Request,
 19→): Promise<Response> {
 20→  const eventType = request.headers.get("x-github-event");
 21→  if (!eventType) {
 22→    return jsonError("missing x-github-event header", 400);
 23→  }
 24→
 25→  if (eventType !== "push") {
 26→    logInfo("webhook.github.skipped", "Non-push event ignored", { eventType });
 27→    return jsonResponse({ accepted: true, reason: "event type not processed" }, 200);
 28→  }
 29→
 30→  const rawBody = await request.text();
 31→
 32→  if (deps.config.githubWebhookSecret) {
 33→    const signature = request.headers.get("x-hub-signature-256");
 34→    if (!signature) {
 35→      return jsonError("missing x-hub-signature-256 header", 401);
 36→    }
 37→
 38→    const valid = await verifyGitHubSignature(deps.config.githubWebhookSecret, rawBody, signature);
 39→    if (!valid) {
 40→      return jsonError("invalid signature", 401);
 41→    }
 42→  }
 43→
 44→  const event = JSON.parse(rawBody) as GitHubPushEvent;
 45→
 46→  if (!event.ref.startsWith("refs/heads/")) {
 47→    logInfo("webhook.github.skipped", "Non-branch push ignored", {
 48→      ref: event.ref,
 49→    });
 50→    return jsonResponse({ accepted: true, reason: "non-branch ref" }, 200);
 51→  }
 52→
 53→  if (event.commits.length === 0) {
 54→    return jsonResponse({ accepted: true, reason: "no commits" }, 200);
 55→  }
 56→
 57→  let workspaceRecord;
 58→  try {
 59→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 60→  } catch {
 61→    return jsonError("workspace not found", 404);
 62→  }
 63→
 64→  logInfo("webhook.github.accepted", "Processing push event", {
 65→    workspaceId,
 66→    repository: event.repository.full_name,
 67→    commitCount: event.commits.length,
 68→  });
 69→
 70→  // Fire-and-forget: process commits asynchronously so we return 200 within GitHub's timeout
 71→  void processGitCommits({
 72→    surreal: deps.surreal,
 73→    extractionModel: deps.extractionModel,
 74→    embeddingModel: deps.embeddingModel,
 75→    embeddingDimension: deps.config.embeddingDimension,
 76→    extractionStoreThreshold: deps.config.extractionStoreThreshold,
 77→    extractionModelId: deps.config.extractionModelId,
 78→    workspaceRecord,
 79→    event,
 80→    autoLinkThreshold: 0.85,
 81→  }).catch((error) => {
 82→    logError("webhook.github.processing_failed", "Commit processing failed", error, {
 83→      workspaceId,
 84→      repository: event.repository.full_name,
 85→    });
 86→  });
 87→
 88→  return jsonResponse({
 89→    accepted: true,
 90→    commitsQueued: event.commits.length,
 91→  }, 202);
 92→}
 93→
 94→async function verifyGitHubSignature(
 95→  secret: string,
 96→  payload: string,
 97→  signature: string,
 98→): Promise<boolean> {
 99→  const encoder = new TextEncoder();
100→  const key = await crypto.subtle.importKey(
101→    "raw",
102→    encoder.encode(secret),
103→    { name: "HMAC", hash: "SHA-256" },
104→    false,
105→    ["sign"],
106→  );
107→  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(payload));
108→  const computed = `sha256=${Buffer.from(sig).toString("hex")}`;
109→
110→  if (computed.length !== signature.length) {
111→    return false;
112→  }
113→
114→  // Constant-time comparison
115→  const a = encoder.encode(computed);
116→  const b = encoder.encode(signature);
117→  if (a.length !== b.length) return false;
118→  let diff = 0;
119→  for (let i = 0; i < a.length; i++) {
120→    diff |= a[i] ^ b[i];
121→  }
122→  return diff === 0;
123→}
