import { describe, expect, it } from "bun:test";
import { extractReferencedTaskIds } from "../../../app/src/server/webhook/commit-task-refs";

/**
 * US-3: brain commit-check parses task refs from commit messages.
 *
 * These tests validate the pure function that extracts task references
 * from commit messages. This is the "fast path" regex parser used by
 * both the CLI commit-check and the GitHub webhook processor.
 */
describe("task reference extraction from commit messages", () => {
  // --- Happy path: single task ref ---

  it("Given a commit message with a single task:id, When parsed, Then the task id is extracted", () => {
    const ids = extractReferencedTaskIds(
      "Implement login flow\n\ntask:abc-1234",
    );
    expect(ids).toEqual(["abc-1234"]);
  });

  it("Given a task ref at the start of the message, When parsed, Then the task id is extracted", () => {
    const ids = extractReferencedTaskIds(
      "task:feat-0042 finalize oauth callback",
    );
    expect(ids).toEqual(["feat-0042"]);
  });

  it("Given a task ref embedded mid-sentence, When parsed, Then the task id is extracted", () => {
    const ids = extractReferencedTaskIds(
      "finalize task:login-7890 oauth callback",
    );
    expect(ids).toEqual(["login-7890"]);
  });

  // --- Happy path: multiple task refs ---

  it("Given a commit with tasks: list, When parsed, Then all task ids are extracted", () => {
    const ids = extractReferencedTaskIds(
      "Batch update\n\ntasks: abc-1234, def-5678",
    );
    expect(ids).toEqual(["abc-1234", "def-5678"]);
  });

  it("Given a commit with both task: and tasks: formats, When parsed, Then all unique ids are extracted", () => {
    const ids = extractReferencedTaskIds(
      "task:abc-1234 cleanup\n\ntasks: abc-1234, ghi-9012",
    );
    expect(ids).toEqual(["abc-1234", "ghi-9012"]);
  });

  it("Given multiple task: tokens in one message, When parsed, Then all are extracted", () => {
    const ids = extractReferencedTaskIds(
      "task:item-001 and also task:item-002 resolved",
    );
    expect(ids).toEqual(["item-001", "item-002"]);
  });

  // --- No refs / edge cases ---

  it("Given a commit message with no task refs, When parsed, Then an empty list is returned", () => {
    const ids = extractReferencedTaskIds("Fix typo in README");
    expect(ids).toEqual([]);
  });

  it("Given a tasks: prefix followed by non-id words, When parsed, Then no ids are extracted", () => {
    const ids = extractReferencedTaskIds("tasks: cleanup docs followups");
    expect(ids).toEqual([]);
  });

  it("Given a commit with only very short tokens after task:, When parsed, Then they are rejected as non-ids", () => {
    const ids = extractReferencedTaskIds("task:abc fix");
    expect(ids).toEqual([]);
  });

  // --- Deduplication ---

  it("Given duplicate task refs in a commit, When parsed, Then each id appears exactly once", () => {
    const ids = extractReferencedTaskIds(
      "task:dup-1111 first mention\ntask:dup-1111 second mention",
    );
    expect(ids).toEqual(["dup-1111"]);
  });

  // --- Boundary: id format validation ---

  it("Given a task ref without digits, When parsed, Then it is rejected", () => {
    const ids = extractReferencedTaskIds("task:refactor");
    expect(ids).toEqual([]);
  });

  it("Given a task ref with hyphens and digits, When parsed, Then it is accepted", () => {
    const ids = extractReferencedTaskIds("task:my-feature-2026");
    expect(ids).toEqual(["my-feature-2026"]);
  });

  it("Given a task ref with underscores, When parsed, Then it is accepted", () => {
    const ids = extractReferencedTaskIds("task:task_20260304_123");
    expect(ids).toEqual(["task_20260304_123"]);
  });
});

import { describe, expect, it } from "bun:test";
import { RecordId } from "surrealdb";
import { createTestUser, fetchJson, setupSmokeSuite } from "../smoke-test-kit";

/**
 * US-1: Agent session creation does not change task status.
 * US-2: Session accept does not change task status.
 *
 * Walking skeleton: Creating a session for a task and accepting it
 * should only affect session lifecycle, never task status.
 * Forward transitions are agent/processor-owned.
 */

const getRuntime = setupSmokeSuite("session-no-status-change");

async function createWorkspaceAndTask(
  baseUrl: string,
  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
  suffix: string,
  taskStatus: string,
) {
  const user = await createTestUser(baseUrl, `session-status-${suffix}`);

  const workspace = await fetchJson<{ workspaceId: string }>(
    `${baseUrl}/api/workspaces`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json", ...user.headers },
      body: JSON.stringify({ name: `Session Status ${Date.now()} ${suffix}` }),
    },
  );

  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
  const taskId = `session-task-${suffix}-${Date.now()}`;
  const taskRecord = new RecordId("task", taskId);

  await surreal.create(taskRecord).content({
    workspace: workspaceRecord,
    title: `Test task for session status ${suffix}`,
    status: taskStatus,
    category: "backend",
    priority: "medium",
    created_at: new Date(),
    updated_at: new Date(),
  });

  return { user, workspace, workspaceRecord, taskId, taskRecord };
}

describe("session creation does not change task status (US-1)", () => {
  // Walking skeleton: session creation preserves task status

  it.skip("Given a task with status 'ready', When an agent session is created for that task, Then the task status remains 'ready' and source_session is linked", async () => {
    const { baseUrl, surreal } = getRuntime();
    const { user, workspace, taskId, taskRecord } = await createWorkspaceAndTask(
      baseUrl, surreal, "ready-1", "ready",
    );

    // Create agent session for the task via MCP endpoint
    const session = await fetchJson<{ session_id: string }>(
      `${baseUrl}/api/mcp/${workspace.workspaceId}/sessions`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ agent: "claude", task_id: taskId }),
      },
    );

    expect(session.session_id).toBeDefined();

    // Verify task status was NOT changed
    const [taskRows] = await surreal
      .query<[Array<{ status: string; source_session?: RecordId }>]>(
        "SELECT status, source_session FROM $task;",
        { task: taskRecord },
      )
      .collect<[Array<{ status: string; source_session?: RecordId }>]>();

    expect(taskRows[0]?.status).toBe("ready");
    expect(taskRows[0]?.source_session).toBeDefined();
  }, 30_000);

  it.skip("Given a task with status 'todo', When an agent session is created for that task, Then the task status remains 'todo'", async () => {
    const { baseUrl, surreal } = getRuntime();
    const { user, workspace, taskId, taskRecord } = await createWorkspaceAndTask(
      baseUrl, surreal, "todo-1", "todo",
    );

    await fetchJson<{ session_id: string }>(
      `${baseUrl}/api/mcp/${workspace.workspaceId}/sessions`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ agent: "claude", task_id: taskId }),
      },
    );

    const [taskRows] = await surreal
      .query<[Array<{ status: string }>]>(
        "SELECT status FROM $task;",
        { task: taskRecord },
      )
      .collect<[Array<{ status: string }>]>();

    expect(taskRows[0]?.status).toBe("todo");
  }, 30_000);

  it.skip("Given a task with status 'in_progress', When an agent session is created, Then the task status remains 'in_progress'", async () => {
    const { baseUrl, surreal } = getRuntime();
    const { user, workspace, taskId, taskRecord } = await createWorkspaceAndTask(
      baseUrl, surreal, "inprog-1", "in_progress",
    );

    await fetchJson<{ session_id: string }>(
      `${baseUrl}/api/mcp/${workspace.workspaceId}/sessions`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ agent: "claude", task_id: taskId }),
      },
    );

    const [taskRows] = await surreal
      .query<[Array<{ status: string }>]>(
        "SELECT status FROM $task;",
        { task: taskRecord },
      )
      .collect<[Array<{ status: string }>]>();

    expect(taskRows[0]?.status).toBe("in_progress");
  }, 30_000);
});

describe("session accept does not change task status (US-2)", () => {
  it.skip("Given a session linked to an in_progress task, When the session is accepted, Then the task status remains 'in_progress'", async () => {
    const { baseUrl, surreal } = getRuntime();
    const { user, workspace, taskId, taskRecord } = await createWorkspaceAndTask(
      baseUrl, surreal, "accept-1", "in_progress",
    );

    // Create session
    const session = await fetchJson<{ session_id: string }>(
      `${baseUrl}/api/mcp/${workspace.workspaceId}/sessions`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ agent: "claude", task_id: taskId }),
      },
    );

    // Accept the session via orchestrator endpoint
    const acceptResult = await fetchJson<{ accepted: boolean }>(
      `${baseUrl}/api/orchestrator/sessions/${session.session_id}/accept`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ summary: "Work completed" }),
      },
    );

    expect(acceptResult.accepted).toBe(true);

    // Verify task status was NOT changed to done
    const [taskRows] = await surreal
      .query<[Array<{ status: string }>]>(
        "SELECT status FROM $task;",
        { task: taskRecord },
      )
      .collect<[Array<{ status: string }>]>();

    expect(taskRows[0]?.status).toBe("in_progress");
  }, 45_000);

  it.skip("Given a session linked to a task already marked 'done', When the session is accepted, Then the task status remains 'done'", async () => {
    const { baseUrl, surreal } = getRuntime();
    const { user, workspace, taskId, taskRecord } = await createWorkspaceAndTask(
      baseUrl, surreal, "accept-2", "done",
    );

    const session = await fetchJson<{ session_id: string }>(
      `${baseUrl}/api/mcp/${workspace.workspaceId}/sessions`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ agent: "claude", task_id: taskId }),
      },
    );

    await fetchJson<{ accepted: boolean }>(
      `${baseUrl}/api/orchestrator/sessions/${session.session_id}/accept`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ summary: "Already done" }),
      },
    );

    const [taskRows] = await surreal
      .query<[Array<{ status: string }>]>(
        "SELECT status FROM $task;",
        { task: taskRecord },
      )
      .collect<[Array<{ status: string }>]>();

    expect(taskRows[0]?.status).toBe("done");
  }, 45_000);
});

import { describe, expect, it } from "bun:test";
import { RecordId } from "surrealdb";
import { createTestUser, fetchJson, setupSmokeSuite } from "../smoke-test-kit";

/**
 * US-3: brain commit-check parses task refs and sets tasks to done.
 *
 * Tests the server endpoint POST /api/mcp/:workspaceId/commits/check
 * which accepts a commit message, extracts task refs (regex fast path),
 * and sets matched tasks to done.
 */

const getRuntime = setupSmokeSuite("commit-check");

async function setupWorkspaceWithTasks(
  baseUrl: string,
  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
  suffix: string,
  tasks: Array<{ id: string; title: string; status: string }>,
) {
  const user = await createTestUser(baseUrl, `commit-check-${suffix}`);

  const workspace = await fetchJson<{ workspaceId: string }>(
    `${baseUrl}/api/workspaces`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json", ...user.headers },
      body: JSON.stringify({ name: `Commit Check ${Date.now()} ${suffix}` }),
    },
  );

  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
  const taskRecords: Array<{ id: string; record: RecordId<"task", string> }> = [];

  for (const task of tasks) {
    const taskRecord = new RecordId("task", task.id);
    await surreal.create(taskRecord).content({
      workspace: workspaceRecord,
      title: task.title,
      status: task.status,
      category: "backend",
      priority: "medium",
      created_at: new Date(),
      updated_at: new Date(),
    });
    taskRecords.push({ id: task.id, record: taskRecord });
  }

  return { user, workspace, workspaceRecord, taskRecords };
}

describe("commit-check endpoint sets tasks to done (US-3)", () => {
  // Walking skeleton: commit with task ref sets task to done

  it.skip("Given a task in_progress and a commit referencing it, When commit-check runs, Then the task status becomes 'done'", async () => {
    const { baseUrl, surreal } = getRuntime();
